using System.IO;
using System.Linq;
using Xunit;

namespace PicoPDF.Test;

public class PngTest
{
    public static readonly string TestDirectory = "../../../../test-case/PngSuite-2017jul19/";

    public static void WriteBitmap(PngFile png, string path)
    {
        var bmp = new BmpFile
        {
            Width = png.Width,
            Height = png.Height,
            Canvas = png.Canvas,
        };
        using var file = File.Create(path);
        bmp.Write(file);
    }

    public static int[] ColorsToInts(Color[] colors)
    {
        return [.. colors.Select(color =>
        {
            var a = color.A / 255F;
            var r = (byte)Math.Round((color.R * a) + (255 * (1 - a)));
            var g = (byte)Math.Round((color.G * a) + (255 * (1 - a)));
            var b = (byte)Math.Round((color.B * a) + (255 * (1 - a)));
            return (r << 16) | (g << 8) | b;
        })];
    }

